import datetime
import email
import imaplib
import json
import re
from collections import OrderedDict
from email.header import decode_header
from email.utils import parsedate_to_datetime
from html.parser import HTMLParser

USER = 'YOUR_EMAIL@example.com'
PASSWORD = 'YOUR_APP_PASSWORD'.replace(' ', '')
HOST = 'YOUR_IMAP_HOST'
PORT = 993
SOCKET_TIMEOUT_SECS = 60
MAX_WARNINGS = 20
MAX_BODY_CHARS = 2000
MAX_MESSAGES_PER_THREAD = 6
MAX_THREAD_TEXT_CHARS = 6000

SUBJECT_PREFIX_RE = re.compile(r'^((re|fw|fwd|aw|sv)\s*:\s*)+', re.I)
URL_RE = re.compile(r'https?://\S+|www\.\S+', re.I)
WHITESPACE_RE = re.compile(r'\s+')
NOISE_RE = re.compile(r'(unsubscribe|manage preferences|view in browser|privacy policy|terms of service)', re.I)


def safe_text(value):
    if value is None:
        return ''
    try:
        return str(value)
    except Exception:
        return ''


def decode_part(part, enc):
    if isinstance(part, str):
        return part
    if not isinstance(part, (bytes, bytearray)):
        return safe_text(part)

    candidates = []
    if enc:
        normalized = safe_text(enc).strip().lower()
        if normalized in {'unknown-8bit', 'unknown', 'x-unknown'}:
            candidates.extend(['utf-8', 'latin-1'])
        else:
            candidates.append(safe_text(enc))

    candidates.extend(['utf-8', 'latin-1'])
    seen = set()
    for candidate in candidates:
        if not candidate or candidate in seen:
            continue
        seen.add(candidate)
        try:
            return bytes(part).decode(candidate, 'replace')
        except Exception:
            continue

    return bytes(part).decode('utf-8', 'replace')


def decode_value(value):
    if not value:
        return ''
    try:
        decoded = decode_header(value)
    except Exception:
        return safe_text(value)

    parts = []
    for item in decoded:
        try:
            if isinstance(item, tuple) and len(item) == 2:
                chunk, enc = item
            else:
                chunk, enc = item, None
            parts.append(decode_part(chunk, enc))
        except Exception:
            parts.append(safe_text(item))
    return ''.join(parts).strip()


def record_warning(warnings, stage, exc, context=''):
    if len(warnings) >= MAX_WARNINGS:
        return
    warnings.append({'stage': stage, 'error': safe_text(exc), 'context': safe_text(context)})


class HTMLTextExtractor(HTMLParser):
    BLOCK_TAGS = {'br', 'p', 'div', 'li', 'tr', 'table', 'section', 'article'}
    SKIP_TAGS = {'script', 'style', 'head', 'svg', 'noscript'}

    def __init__(self):
        super().__init__()
        self.parts = []
        self.skip_depth = 0

    def handle_starttag(self, tag, attrs):
        tag = (tag or '').lower()
        if tag in self.SKIP_TAGS:
            self.skip_depth += 1
            return
        if not self.skip_depth and tag in self.BLOCK_TAGS:
            self.parts.append('\n')

    def handle_endtag(self, tag):
        tag = (tag or '').lower()
        if tag in self.SKIP_TAGS and self.skip_depth:
            self.skip_depth -= 1
            return
        if not self.skip_depth and tag in self.BLOCK_TAGS:
            self.parts.append('\n')

    def handle_data(self, data):
        if self.skip_depth:
            return
        if data:
            self.parts.append(data)

    def text(self):
        return ''.join(self.parts)


def collapse_text(text):
    text = safe_text(text)
    text = text.replace('\u00a0', ' ')
    text = text.replace('\r', '\n')
    text = URL_RE.sub(' ', text)
    lines = []
    for raw_line in text.split('\n'):
        cleaned = WHITESPACE_RE.sub(' ', raw_line).strip()
        if not cleaned:
            continue
        if NOISE_RE.search(cleaned) and len(cleaned) < 160:
            continue
        lines.append(cleaned)
    collapsed = '\n'.join(lines).strip()
    if len(collapsed) > MAX_BODY_CHARS:
        trimmed = collapsed[:MAX_BODY_CHARS].rstrip()
        if ' ' in trimmed:
            trimmed = trimmed.rsplit(' ', 1)[0]
        collapsed = trimmed.rstrip(' .,;:') + ' ...'
    return collapsed


def html_to_text(raw_html):
    parser = HTMLTextExtractor()
    try:
        parser.feed(raw_html)
        parser.close()
    except Exception:
        return collapse_text(raw_html)
    return collapse_text(parser.text())


def extract_body_text(msg):
    plain_parts = []
    html_parts = []

    def add_part(content_type, payload, charset):
        if not payload:
            return
        decoded = decode_part(payload, charset)
        if content_type == 'text/plain':
            plain_parts.append(decoded)
        elif content_type == 'text/html':
            html_parts.append(decoded)

    if msg.is_multipart():
        for part in msg.walk():
            disposition = safe_text(part.get('Content-Disposition')).lower()
            if 'attachment' in disposition:
                continue
            content_type = safe_text(part.get_content_type()).lower()
            if content_type not in {'text/plain', 'text/html'}:
                continue
            try:
                payload = part.get_payload(decode=True)
            except Exception:
                payload = None
            add_part(content_type, payload, part.get_content_charset())
    else:
        try:
            payload = msg.get_payload(decode=True)
        except Exception:
            payload = None
        add_part(safe_text(msg.get_content_type()).lower(), payload, msg.get_content_charset())

    plain_text = collapse_text('\n\n'.join(plain_parts)) if plain_parts else ''
    html_text = html_to_text('\n\n'.join(html_parts)) if html_parts else ''

    if len(plain_text) >= 40:
        return plain_text
    return html_text or plain_text


def normalize_subject(subject):
    subject = collapse_text(subject)
    while True:
        stripped = SUBJECT_PREFIX_RE.sub('', subject).strip()
        if stripped == subject:
            return stripped or '(no subject)'
        subject = stripped


def parse_date(value, warnings):
    raw = decode_value(value)
    if not raw:
        return None, None
    try:
        dt = parsedate_to_datetime(raw)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=datetime.timezone.utc)
        dt_utc = dt.astimezone(datetime.timezone.utc)
        return raw, dt_utc
    except Exception as exc:
        record_warning(warnings, 'parse_date', exc, raw)
        return raw, None


def build_thread_key(msg, normalized_subject, message_id, imap_id):
    references = decode_value(msg.get('References'))
    if references:
        first_ref = references.split()[0].strip('<>')
        if first_ref:
            return 'ref:' + first_ref, references, decode_value(msg.get('In-Reply-To'))

    in_reply_to = decode_value(msg.get('In-Reply-To'))
    if in_reply_to:
        return 'reply:' + in_reply_to.strip('<>'), references, in_reply_to

    if normalized_subject:
        return 'subj:' + normalized_subject.lower(), references, in_reply_to

    if message_id:
        return 'msg:' + message_id.strip('<>'), references, in_reply_to

    return 'imap:' + imap_id, references, in_reply_to


cutoff_utc = datetime.datetime.now(datetime.timezone.utc) - datetime.timedelta(hours=24)
since_date = cutoff_utc.strftime('%d-%b-%Y')
mail = None
warnings = []
messages = []
seen_messages = set()

try:
    mail = imaplib.IMAP4_SSL(HOST, PORT, timeout=SOCKET_TIMEOUT_SECS)
    mail.login(USER, PASSWORD)
    mail.select('INBOX')

    status, data = mail.search(None, f'(SINCE "{since_date}")')
    message_ids = data[0].split() if status == 'OK' and data and data[0] else []

    for message_id in message_ids:
        imap_id = message_id.decode(errors='ignore')
        try:
            fetch_status, msg_data = mail.fetch(message_id, '(BODY.PEEK[])')
            if fetch_status != 'OK' or not msg_data:
                continue

            raw_msg = None
            for part in msg_data:
                if isinstance(part, tuple) and len(part) > 1:
                    raw_msg = part[1]
                    break
            if not raw_msg:
                continue

            try:
                msg = email.message_from_bytes(raw_msg)
            except Exception as exc:
                record_warning(warnings, 'parse_message', exc, imap_id)
                continue

            raw_date, parsed_dt_utc = parse_date(msg.get('Date'), warnings)
            if parsed_dt_utc is not None and parsed_dt_utc < cutoff_utc:
                continue

            subject = decode_value(msg.get('Subject')) or '(no subject)'
            normalized_subject = normalize_subject(subject)
            message_id_value = decode_value(msg.get('Message-ID'))
            from_value = decode_value(msg.get('From'))
            to_value = decode_value(msg.get('To'))
            body_text = extract_body_text(msg)
            thread_key, references_value, in_reply_to = build_thread_key(msg, normalized_subject, message_id_value, imap_id)
            dedupe_key = (message_id_value or imap_id, thread_key)
            if dedupe_key in seen_messages:
                continue
            seen_messages.add(dedupe_key)

            messages.append({
                'imapId': imap_id,
                'messageId': message_id_value,
                'from': from_value,
                'to': to_value,
                'subject': subject,
                'normalizedSubject': normalized_subject,
                'date': raw_date,
                'dateIsoUtc': parsed_dt_utc.isoformat() if parsed_dt_utc else None,
                'references': references_value,
                'inReplyTo': in_reply_to,
                'threadKey': thread_key,
                'bodyPreview': body_text,
            })
        except Exception as exc:
            record_warning(warnings, 'process_email', exc, imap_id)
            continue
finally:
    if mail is not None:
        try:
            mail.logout()
        except Exception:
            pass

messages.sort(key=lambda item: (item.get('dateIsoUtc') or '', item.get('imapId') or ''))
threads_map = OrderedDict()
for item in messages:
    thread = threads_map.setdefault(item['threadKey'], {
        'threadKey': item['threadKey'],
        'normalizedSubject': item.get('normalizedSubject') or normalize_subject(item.get('subject')),
        'messages': [],
    })
    thread['messages'].append(item)

threads = []
for thread in threads_map.values():
    original_messages = list(thread['messages'])
    trimmed_messages = original_messages[-MAX_MESSAGES_PER_THREAD:]
    conversation_parts = []
    total_chars = 0
    for idx, msg in enumerate(trimmed_messages, start=1):
        block = [
            f'Message {idx}',
            'Date: ' + safe_text(msg.get('dateIsoUtc') or msg.get('date') or '-'),
            'From: ' + safe_text(msg.get('from') or '-'),
            'Subject: ' + safe_text(msg.get('subject') or '-'),
            'Body: ' + safe_text(msg.get('bodyPreview') or '(no readable body)'),
        ]
        chunk = '\n'.join(block)
        if total_chars and total_chars + len(chunk) + 2 > MAX_THREAD_TEXT_CHARS:
            break
        conversation_parts.append(chunk)
        total_chars += len(chunk) + 2

    latest = original_messages[-1]
    thread_payload = {
        'threadKey': thread['threadKey'],
        'normalizedSubject': thread['normalizedSubject'],
        'latestSubject': latest.get('subject') or thread['normalizedSubject'],
        'latestFrom': latest.get('from') or '',
        'firstDateIsoUtc': original_messages[0].get('dateIsoUtc'),
        'lastDateIsoUtc': latest.get('dateIsoUtc'),
        'messageCount': len(original_messages),
        'messages': trimmed_messages,
        'conversationText': '\n\n'.join(conversation_parts).strip(),
    }
    threads.append(thread_payload)

threads.sort(key=lambda item: item.get('lastDateIsoUtc') or '', reverse=True)

result = {
    'generatedAtUtc': datetime.datetime.now(datetime.timezone.utc).isoformat(),
    'windowHours': 24,
    'count': len(messages),
    'threadCount': len(threads),
    'emails': messages,
    'threads': threads,
}

if warnings:
    result['warningCount'] = len(warnings)
    result['warnings'] = warnings

print(json.dumps(result, ensure_ascii=False))
