const raw = ($json.stdout ?? '').trim();
if (!raw) {
  return [{ json: { generatedAtUtc: new Date().toISOString(), windowHours: 24, count: 0, emails: [], note: 'No stdout from command', stderr: $json.stderr ?? '' } }];
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error(`Failed to parse command stdout as JSON: ${raw.slice(0, 500)}`);
}

return [{ json: parsed }];

const payload = $json ?? {};
const threadsInput = Array.isArray(payload.threads) ? payload.threads : [];
const emails = Array.isArray(payload.emails) ? payload.emails : [];
const totalEmailCount = Number(payload.count ?? emails.length ?? 0);
const totalThreadCount = Number(payload.threadCount ?? threadsInput.length ?? 0);

const clean = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const clip = (value, max) => {
  const text = clean(value);
  if (!text || text.length <= max) return text;
  const trimmed = text.slice(0, max).trim();
  return trimmed.replace(/[\s.,;:]+$/g, '') + ' ...';
};
const dedupeBy = (items, keyFn) => {
  const seen = new Set();
  return items.filter((item) => {
    const key = keyFn(item);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
};

const synthThreads = emails.map((email) => ({
  threadKey: email.threadKey || email.messageId || email.imapId || clean(email.subject) || 'single',
  normalizedSubject: clean(email.normalizedSubject || email.subject || '(no subject)'),
  latestSubject: clean(email.subject || '(no subject)'),
  latestFrom: clean(email.from || ''),
  firstDateIsoUtc: email.dateIsoUtc || null,
  lastDateIsoUtc: email.dateIsoUtc || null,
  messageCount: 1,
  messages: [email],
  conversationText: [
    `Message 1`,
    `Date: ${clean(email.dateIsoUtc || email.date || '-')}`,
    `From: ${clean(email.from || '-')}`,
    `Subject: ${clean(email.subject || '(no subject)')}`,
    `Body: ${clean(email.bodyPreview || '(no readable body)')}`,
  ].join('\n'),
}));

const threads = (threadsInput.length ? threadsInput : synthThreads)
  .map((thread, index) => ({
    index,
    threadKey: clean(thread.threadKey || `thread-${index + 1}`),
    normalizedSubject: clean(thread.normalizedSubject || thread.latestSubject || '(no subject)'),
    latestSubject: clean(thread.latestSubject || thread.normalizedSubject || '(no subject)'),
    latestFrom: clean(thread.latestFrom || thread.messages?.slice(-1)?.[0]?.from || ''),
    messageCount: Number(thread.messageCount ?? (Array.isArray(thread.messages) ? thread.messages.length : 0) ?? 1),
    firstDateIsoUtc: clean(thread.firstDateIsoUtc || ''),
    lastDateIsoUtc: clean(thread.lastDateIsoUtc || ''),
    conversationText: clip(thread.conversationText || '', 6000),
  }))
  .filter((thread) => thread.latestSubject || thread.conversationText);

const blockedPatterns = [
  /job alert|jobalerts|recommended jobs?|is hiring|hiring digest|career opportunity|open roles?|bootcamp/i,
  /newsletter|digest|promo|promotion|offer|discount|deal|sale|coupon|advert|marketing/i,
  /loan|credit card|pre-?approved|ipo\b|nfo\b|mutual fund\s*nfo|market digest|stock alert|webinar|contest|preorder/i,
  /people you may know|social update|linkedin (news|update|research|group|notification)/i,
  /welcome to|product update|release notes|new in|free trial reminder/i,
];
const urgentPatterns = [
  /security alert|suspicious|verify|verification|otp|2fa|password|breach|sign-?in/i,
  /action required|urgent|deadline|due today|due tomorrow|expires?|expiry|renew/i,
  /confirm|approval|approve|reply required|respond by|complete your/i,
  /payment due|invoice|failed payment|billing issue|statement available/i,
  /meeting|rescheduled|calendar|client issue|incident|outage|support ending/i,
];
const infoPatterns = [
  /statement|receipt|transaction confirmed|order shipped|delivery update|storage/i,
  /notice|policy update|digest|summary|market note|report/i,
];

const classifyReason = (thread) => {
  const text = `${thread.latestSubject} ${thread.latestFrom} ${thread.conversationText}`;
  if (/security alert|verify|otp|2fa|password|sign-?in/i.test(text)) return 'Security verification or review needed';
  if (/confirm|approval|approve|reply required|respond by|complete your/i.test(text)) return 'Pending confirmation or reply from you';
  if (/payment due|invoice|failed payment|billing issue/i.test(text)) return 'Payment or billing action required';
  if (/meeting|rescheduled|calendar|deadline|due/i.test(text)) return 'Schedule or deadline requires attention';
  if (/renew|expires?|support ending/i.test(text)) return 'Expiry or renewal needs action';
  return 'Review and act on this thread';
};
const infoNote = (thread) => {
  const text = `${thread.latestSubject} ${thread.latestFrom} ${thread.conversationText}`;
  if (/statement|receipt|transaction confirmed/i.test(text)) return 'Informational financial update';
  if (/delivery|order shipped/i.test(text)) return 'Delivery or order status update';
  if (/notice|policy update|report/i.test(text)) return 'Informational notice';
  return 'Useful for reference';
};

const annotated = threads.map((thread) => {
  const haystack = `${thread.latestSubject} ${thread.latestFrom} ${thread.conversationText}`;
  const isBlocked = blockedPatterns.some((rx) => rx.test(haystack));
  const isUrgent = urgentPatterns.some((rx) => rx.test(haystack));
  const isInfo = !isBlocked && !isUrgent && infoPatterns.some((rx) => rx.test(haystack));
  return { ...thread, isBlocked, isUrgent, isInfo };
});

const blockedThreads = annotated.filter((thread) => thread.isBlocked);
const candidateThreads = annotated.filter((thread) => !thread.isBlocked);
const urgentThreads = dedupeBy(candidateThreads.filter((thread) => thread.isUrgent), (thread) => thread.normalizedSubject.toLowerCase()).slice(0, 5);
const infoThreads = dedupeBy(candidateThreads.filter((thread) => !thread.isUrgent && thread.isInfo), (thread) => thread.normalizedSubject.toLowerCase()).slice(0, 3);

const maxCandidateThreads = 12;
const maxContextChars = 24000;
let consumedChars = 0;
const candidateThreadContext = [];
for (const thread of candidateThreads.slice(0, maxCandidateThreads)) {
  const block = [
    `Thread Key: ${thread.threadKey}`,
    `Normalized Subject: ${thread.normalizedSubject}`,
    `Latest Subject: ${thread.latestSubject}`,
    `Latest Sender: ${thread.latestFrom || '-'}`,
    `Message Count: ${thread.messageCount}`,
    `Last Email UTC: ${thread.lastDateIsoUtc || '-'}`,
    `Conversation:\n${thread.conversationText || '(no readable body)'}`,
  ].join('\n');
  if (consumedChars && consumedChars + block.length + 2 > maxContextChars) break;
  candidateThreadContext.push(block);
  consumedChars += block.length + 2;
}

const blockedExamples = blockedThreads.slice(0, 4).map((thread) => `${thread.latestSubject} (${thread.latestFrom || 'unknown sender'})`);
const urgentItems = urgentThreads.map((thread) => ({
  subject: thread.latestSubject,
  sender: thread.latestFrom || 'Unknown sender',
  reason: classifyReason(thread),
}));
const forInfo = infoThreads.map((thread) => ({
  subject: thread.latestSubject,
  sender: thread.latestFrom || 'Unknown sender',
  note: infoNote(thread),
}));

const fallbackSummary = urgentItems.length
  ? `${urgentItems.length} email thread${urgentItems.length === 1 ? '' : 's'} need action from the last 24 hours.`
  : 'No actionable email threads in the last 24 hours.';

const fallbackStructured = {
  summary: fallbackSummary,
  urgent_items: urgentItems,
  for_info: forInfo,
};

const dateLocal = new Intl.DateTimeFormat(undefined, {
  day: '2-digit',
  month: 'short',
  year: 'numeric',
}).format(new Date());

return {
  json: {
    ...payload,
    total_thread_count: totalThreadCount || threads.length,
    email_count_24h: totalEmailCount,
    blocked_thread_count: blockedThreads.length,
    candidate_thread_count: candidateThreads.length,
    blocked_examples_text: blockedExamples.join('; '),
    candidate_thread_context: candidateThreadContext.join('\n\n'),
    fallback_structured: fallbackStructured,
    ntfy_title: `Daily Email Summary | ${totalEmailCount} mails | ${dateLocal}`,
  },
};

const base = $json || {};
const structured = base.structured_output || {};
const urgentItems = Array.isArray(base.urgent_items) ? base.urgent_items : Array.isArray(structured.urgent_items) ? structured.urgent_items : [];
const forInfo = Array.isArray(base.for_info) ? base.for_info : Array.isArray(structured.for_info) ? structured.for_info : [];
const summary = String(base.summary || structured.summary || 'Action needed on recent email threads.').trim();
const mutedCount = Number(base.blocked_thread_count ?? 0);
const mutedExamples = String(base.blocked_examples_text || '').trim();

const clean = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const clip = (value, max) => {
  const text = clean(value);
  if (!text || text.length <= max) return text;
  return text.slice(0, max).replace(/[\s.,;:]+$/g, '') + ' ...';
};
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const wrap = (value, width) => {
  const text = clean(value);
  if (!text) return [''];
  const tokens = text.split(/\s+/);
  const lines = [];
  let current = '';
  for (const token of tokens) {
    if (token.length > width) {
      if (current) {
        lines.push(current);
        current = '';
      }
      for (let i = 0; i < token.length; i += width) lines.push(token.slice(i, i + width));
      continue;
    }
    if (!current) {
      current = token;
      continue;
    }
    if ((current + ' ' + token).length <= width) {
      current += ' ' + token;
    } else {
      lines.push(current);
      current = token;
    }
  }
  if (current) lines.push(current);
  return lines.length ? lines : [''];
};

const columns = [
  { key: 'subject', width: 26 },
  { key: 'sender', width: 18 },
  { key: 'reason', width: 30 },
];
const border = '+' + columns.map((c) => '-'.repeat(c.width + 2)).join('+') + '+';
const renderBlock = (row) => {
  const cellLines = columns.map((column) => wrap(row[column.key] ?? '', column.width));
  const height = Math.max(...cellLines.map((lines) => lines.length));
  return Array.from({ length: height }, (_, index) => {
    const cells = columns.map((column, cellIndex) => ` ${(cellLines[cellIndex][index] || '').padEnd(column.width, ' ')} `);
    return `|${cells.join('|')}|`;
  });
};
const buildTable = (rows) => {
  if (!rows.length) return 'None';
  const lines = [border, ...renderBlock({ subject: 'Subject', sender: 'Sender', reason: 'Reason' }), border];
  for (const row of rows.slice(0, 5)) {
    lines.push(...renderBlock({
      subject: clip(row.subject, 240),
      sender: clip(row.sender, 140),
      reason: clip(row.reason, 220),
    }));
    lines.push(border);
  }
  return ['```', ...lines, '```'].join('\n');
};

const infoLines = forInfo.slice(0, 3).map((item) => `- ${clip(item.subject, 90)} | ${clip(item.sender, 60)} | ${clip(item.note, 90)}`);
const mutedLines = [
  `- ${mutedCount} thread${mutedCount === 1 ? '' : 's'} muted before analysis.`,
  mutedExamples ? `- Examples: ${clip(mutedExamples, 240)}` : '- Examples: None',
];

const sections = [
  '📬 Daily Email Summary (Last 24h)',
  '🧠 Summary',
  summary,
  '',
  '✅ Action Required',
  buildTable(urgentItems),
];
if (infoLines.length) {
  sections.push('', 'ℹ️ For Info', ...infoLines);
}
sections.push('', '🧹 Muted', ...mutedLines);

const text = sections.join('\n').trim();
const codeBlockRegex = /```(?:[a-zA-Z0-9_-]+)?\n?([\s\S]*?)```/g;
let html = '';
let lastIndex = 0;
let match;
while ((match = codeBlockRegex.exec(text)) !== null) {
  html += escapeHtml(text.slice(lastIndex, match.index));
  html += `<pre>${escapeHtml(String(match[1] ?? '').replace(/^\n+|\n+$/g, ''))}</pre>`;
  lastIndex = match.index + match[0].length;
}
html += escapeHtml(text.slice(lastIndex));

return {
  json: {
    ...base,
    text,
    notify_message: text,
    telegram_message: html || escapeHtml(text),
  },
};

const base = (() => {
  try {
    return $('Prepare Structured Prompt').first().json || {};
  } catch {
    return {};
  }
})();
const payload = $json || {};
const fallback = base.fallback_structured || { summary: 'No actionable email threads in the last 24 hours.', urgent_items: [], for_info: [] };

const clean = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const clip = (value, max) => {
  const text = clean(value);
  if (!text || text.length <= max) return text;
  return text.slice(0, max).replace(/[\s.,;:]+$/g, '') + ' ...';
};
const normalizeItem = (item, noteKey) => ({
  subject: clip(item?.subject, 180),
  sender: clip(item?.sender, 140),
  [noteKey]: clip(item?.[noteKey], 90),
});
const extractJsonObject = (text) => {
  const source = String(text || '').trim();
  if (!source) return null;
  try {
    return JSON.parse(source);
  } catch {}
  let depth = 0;
  let start = -1;
  let inString = false;
  let escaped = false;
  for (let i = 0; i < source.length; i += 1) {
    const ch = source[i];
    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === '\\' && inString) {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;
    if (ch === '{') {
      if (depth === 0) start = i;
      depth += 1;
    } else if (ch === '}') {
      if (depth > 0) depth -= 1;
      if (depth === 0 && start !== -1) {
        const candidate = source.slice(start, i + 1);
        try {
          return JSON.parse(candidate);
        } catch {
          start = -1;
        }
      }
    }
  }
  return null;
};

const rawCandidates = [
  payload?.message?.content,
  payload?.response?.message?.content,
  payload?.data?.message?.content,
  payload?.output,
  payload?.response,
  payload?.text,
  payload,
];

let structured = null;
let rawModelText = '';
for (const candidate of rawCandidates) {
  if (!candidate) continue;
  if (typeof candidate === 'string') {
    rawModelText = rawModelText || candidate;
    const parsed = extractJsonObject(candidate);
    if (parsed) {
      structured = parsed;
      break;
    }
    continue;
  }
  if (typeof candidate === 'object') {
    const direct = candidate.summary || candidate.urgent_items || candidate.for_info ? candidate : null;
    if (direct) {
      structured = direct;
      break;
    }
    const nestedText = candidate?.message?.content || candidate?.content || '';
    if (nestedText && typeof nestedText === 'string') {
      rawModelText = rawModelText || nestedText;
      const parsed = extractJsonObject(nestedText);
      if (parsed) {
        structured = parsed;
        break;
      }
    }
  }
}

if (!structured || typeof structured !== 'object') {
  const urgentItems = Array.isArray(fallback.urgent_items) ? fallback.urgent_items : [];
  const forInfo = Array.isArray(fallback.for_info) ? fallback.for_info : [];
  return {
    json: {
      ...base,
      ...payload,
      structured_output: fallback,
      summary: clean(fallback.summary),
      urgent_items: urgentItems,
      for_info: forInfo,
      has_urgent_items: urgentItems.length > 0,
      summary_source: 'ollama_fallback_invalid_output',
      ollama_error: 'Model returned invalid JSON; heuristic fallback used.',
      raw_model_text: clip(rawModelText, 3000),
    },
  };
}

const summary = clip(structured.summary || fallback.summary, 140);
const urgentItems = (Array.isArray(structured.urgent_items) ? structured.urgent_items : [])
  .map((item) => normalizeItem(item, 'reason'))
  .filter((item) => item.subject && item.sender && item.reason)
  .slice(0, 5);
const forInfo = (Array.isArray(structured.for_info) ? structured.for_info : [])
  .map((item) => normalizeItem(item, 'note'))
  .filter((item) => item.subject && item.sender && item.note)
  .slice(0, 3);
const normalized = {
  summary: summary || fallback.summary,
  urgent_items: urgentItems,
  for_info: forInfo,
};

return {
  json: {
    ...base,
    ...payload,
    structured_output: normalized,
    summary: normalized.summary,
    urgent_items: normalized.urgent_items,
    for_info: normalized.for_info,
    has_urgent_items: normalized.urgent_items.length > 0,
    summary_source: 'ollama_structured',
    ollama_error: '',
    raw_model_text: clip(rawModelText, 3000),
  },
};
